import{_ as e,o as t,c as s,a2 as r}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"LLM 강의 콘텐츠 임포트 자동화","description":"","frontmatter":{"title":"LLM 강의 콘텐츠 임포트 자동화","feature_id":"012","status":"done","created":"2026-06-03 14:52 (KST)","date":"2026-06-03T00:00:00.000Z","tags":["tooling","content-migration","llm","rag","vitepress","automation"]},"headers":[],"relativePath":"specs/012-llm-course-import/spec.md","filePath":"specs/012-llm-course-import/spec.md","lastUpdated":null}'),c={name:"specs/012-llm-course-import/spec.md"};function i(d,o,n,l,a,g){return t(),s("div",null,[...o[0]||(o[0]=[r('<h1 id="spec-llm-강의-콘텐츠-임포트-자동화" tabindex="-1">Spec: LLM 강의 콘텐츠 임포트 자동화 <a class="header-anchor" href="#spec-llm-강의-콘텐츠-임포트-자동화" aria-label="Permalink to &quot;Spec: LLM 강의 콘텐츠 임포트 자동화&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p><code>../llm-main</code> 에는 LangChain·Ollama·임베딩·RAG·LangGraph 를 다루는 한국어 LLM/RAG 강의 시리즈가 들어 있다(강의 본문 <code>m101~m135</code> 약 45편, 각 강의의 실행 예제 <code>.py</code> 약 46개, 이미지 자산 등). 이 강의 콘텐츠를 현재 VitePress 사이트로 옮겨 <strong>한 곳에서 함께 게시·검색·관리</strong>하고, 블로그 방문자가 강의 시리즈로 읽을 수 있게 하고 싶다.</p><p>문제는 <code>../llm-main</code> 이 강의 게시용으로 정리된 형태가 아니라는 점이다.</p><ul><li><strong>프런트매터 부재</strong>: 모든 강의 <code>.md</code> 에 프런트매터가 <strong>없다</strong>. 제목은 본문 첫 헤딩에 들어 있고(예: <code># LangGraph로 조건 분기 워크플로우 구현하기</code>), 일부 초기 강의는 <code>### 💻 환경 구성</code> 처럼 섹션형 헤딩만 있다. VitePress 게시·정렬에 필요한 제목·작성일시 메타가 없다.</li><li><strong>이미지 경로 불일치</strong>: 본문은 이미지를 <code>![](app/static/101_1.png)</code> 처럼 <code>app/static/</code> 접두로 가리키지만, 실제 파일은 <code>static/101_1.png</code> 에 있다(접두 <code>app/</code> 가 실재하지 않음). 그대로 옮기면 VitePress 에서 전부 깨진다.</li><li><strong>예제 코드 분리</strong>: 강의 본문에는 코드가 펜스 블록으로 들어 있고, 실행 가능한 전체 예제는 별도 <code>m*.py</code> 파일로 존재한다(강의↔예제 1:1~1:N).</li><li><strong>비-게시 자산 혼재</strong>: 벡터DB·CSV·<code>.langchain.db</code>·Streamlit 앱·Jupyter 노트북 등 강의 본문이 아닌 대용량/실험 자산이 한 폴더에 섞여 있다.</li></ul><p>이걸 손으로 옮기는 것은 실수가 잦고 재현이 안 된다. 이미 이 저장소에는 Hexo 블로그를 임포트하는 <a href="./../008-hexo-blog-import/spec"><code>specs/008-hexo-blog-import</code></a> 와 <code>scripts/sync-*.{ps1,sh}</code> 같은 <strong>반복 실행 가능한 임포트 스크립트</strong> 선례가 있다. 같은 방식으로, <strong>원본을 건드리지 않고 한 번의 명령으로 강의 시리즈 전체를 VitePress <code>/llm/</code> 섹션으로 변환·복사하는 자동화 스크립트</strong>가 필요하다.</p><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-03" tabindex="-1">Session 2026-06-03 <a class="header-anchor" href="#session-2026-06-03" aria-label="Permalink to &quot;Session 2026-06-03&quot;">​</a></h3><ul><li>Q: <code>../llm-main</code> 에서 본 블로그로 가져올 콘텐츠 범위는? → A: <strong>강의 <code>.md</code> + 참조 이미지 + 예제 <code>.py</code> 소스</strong>를 포함한다. Jupyter 노트북(<code>docs/</code>)과 대용량 데이터 산출물(CSV·벡터DB·<code>.langchain.db</code> 등)은 <strong>제외</strong>한다.</li><li>Q: 임포트한 LLM 강의를 사이트 어디에 배치할까? → A: <strong>전용 <code>/llm/</code> 섹션을 신설</strong>한다. 008(hexo-import)처럼 생성물을 커밋해 CI 가 소비하며, 사이드바·상단 내비에 새 섹션으로 등록한다.</li><li>Q: 프런트매터가 없는 각 강의의 <code>created</code>/<code>date</code> 값을 무엇으로 채울까? → A: <strong>강의 번호 기반 가상 일자</strong> — 강의 번호(<code>mNNN[.k]</code>) 순서대로 <code>created</code>/<code>date</code> 가 단조 증가하도록 부여한다. 정렬은 FR-3 대로 번호 오름차순이며, 이 값은 표기· frontmatter 유효성용이다(번호 순서와 일관).</li><li>Q: 각 강의의 실행 예제 <code>m*.py</code> 소스를 어떻게 노출할까? → A: <strong>강의 본문 말미에 인라인</strong> — 각 강의 페이지 끝에 &quot;전체 예제 코드&quot; 코드펜스로 삽입해 페이지 이동 없이 강의와 전체 코드를 함께 본다. 예제가 여럿이면 모두 인라인하고, 없으면 생략한다.</li><li>Q: <code>/llm/</code> 섹션 사이드바를 어떻게 구성할까? → A: <strong>번호순 평면 목록</strong> — <code>m101</code>→<code>m135</code> 를 번호 오름차순 단일 리스트로 나열한다(주제별 그룹화 안 함). 원본 에 카테고리 메타가 없어 가장 충실·저위험.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ul><li><code>../llm-main</code> 의 모든 강의 본문 <code>m*.md</code>(약 45편)를 VitePress 사이트의 새 최상위 섹션 <code>/llm/</code> 으로 변환·복사한다.</li><li>프런트매터가 없는 각 강의에 VitePress 호환 프런트매터를 <strong>생성</strong>한다 — 제목은 본문 첫 헤딩에서 도출하고, 본 저장소 규칙에 맞춰 <code>created</code>(시각 포함)·<code>date</code> 를 부여한다.</li><li>각 강의가 참조하는 이미지를 모두 찾아 사이트 정적 자산 위치로 복사하고, 본문 이미지 링크의 경로 불일치(<code>app/static/X</code> → 실제 <code>static/X</code>)를 해소해 VitePress 에서 작동하는 <strong>표준 마크다운 이미지</strong>로 재작성한다.</li><li>각 강의의 실행 예제 <code>m*.py</code> 소스를 함께 임포트하여, 해당 강의에서 전체 실행 코드를 <strong>보거나 받을 수 있게</strong> 연결한다(강의↔예제 매핑 보존).</li><li>강의 번호(<code>mNNN[.k]</code>) 기반의 <strong>학습 순서</strong>를 메뉴/목록에 보존한다(아래 Assumptions 의 정렬 예외 참조).</li><li>새 섹션의 진입 인덱스(<code>index.md</code>)와 사이드바·상단 내비게이션 항목을 생성/등록해, 기존 cowork·hermes·blog-archive 섹션과 같은 방식으로 노출한다.</li><li>변환 결과가 VitePress <strong>strict 빌드</strong>(<code>npm run build</code>)를 깨지 않게 한다(깨진 내부 링크 0, <code>{{ }}</code> 등 Vue 템플릿 충돌 회피).</li><li>스크립트는 <strong>재실행 가능(idempotent)</strong> 해야 한다 — 다시 돌려도 중복·찌꺼기 없이 같은 결과가 나온다.</li><li>실행 후 요약 리포트를 출력한다(변환된 강의 수, 복사된 이미지 수, 연결된 예제 수, 건너뛴/실패 항목과 사유).</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>원본(<code>../llm-main</code>)을 수정하지 않는다(읽기 전용 소스).</li><li>Jupyter 노트북(<code>docs/**/*.ipynb</code>)은 이번 임포트 대상이 아니다.</li><li>대용량/실험 데이터 산출물(<code>auigrid_*.csv</code>, <code>auigrid_vectordb*</code>, <code>auigrid_vector_db_final</code>, <code>.langchain.db</code>, <code>lang.db</code>, <code>fail_urls.csv</code> 등)은 옮기지 않는다.</li><li>Streamlit 앱·유틸 스크립트(<code>auidemo.py</code>, <code>blog.py</code>, <code>main.py</code>, <code>openai_utils.py</code>, <code>create_vector.py</code>, <code>step1.py</code>, <code>retry.py</code> 등 강의 예제가 아닌 운영/생성 스크립트)는 옮기지 않는다.</li><li>강의 내용 자체의 교정·재작성·번역은 하지 않는다(형식 변환과 메타 생성만).</li><li>예제 코드의 실제 실행·검증(LLM 호출, 임베딩 생성 등)은 다루지 않는다(코드는 텍스트 자산으로만 취급).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>As a</strong> 저장소 관리자, <strong>I want</strong> 한 번의 명령으로 <code>../llm-main</code> 의 강의 시리즈 전체를 VitePress 사이트에 임포트, <strong>so that</strong> 강의를 별도로 운영하지 않고 블로그 한 곳에서 게시·관리할 수 있다.</li><li><strong>As a</strong> 독자, <strong>I want</strong> <code>/llm/</code> 섹션에서 강의를 학습 순서대로 읽고 각 강의의 이미지·예제 코드를 정상적으로 보기를, <strong>so that</strong> 원본과 동일하게 강의를 따라갈 수 있다.</li><li><strong>As a</strong> 관리자, <strong>I want</strong> 원본에 강의를 추가/수정한 뒤 스크립트를 다시 돌려도 안전하게 결과가 갱신되기를, <strong>so that</strong> 재현 가능하게 재동기화할 수 있다.</li><li><strong>As a</strong> 관리자, <strong>I want</strong> 실행 후 무엇이 옮겨졌고 무엇이 실패했는지 요약을 보기를, <strong>so that</strong> 누락이나 깨진 변환을 바로 확인할 수 있다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>FR-1</strong>: 스크립트는 소스 경로(기본 <code>../llm-main</code>)에서 강의 본문 <code>m*.md</code>(예: <code>m101.md</code>, <code>m107.0.md</code>, <code>m135.md</code>) 전부를 발견하여 처리한다.</li><li><strong>FR-2</strong>: 프런트매터가 없는 각 강의에 VitePress 호환 프런트매터를 생성한다. 최소한 제목과 작성일시(<code>created</code>/<code>date</code>)를 부여하며, 제목은 본문 첫 헤딩에서 도출한다. 첫 헤딩이 일반 제목이 아닌 섹션형(예: <code>### 💻 환경 구성</code>)인 강의는 강의 번호와 헤딩 텍스트를 조합한 안정적 제목 규칙을 적용한다. <code>created</code>/<code>date</code> 는 <strong>강의 번호 순서대로 단조 증가하는 가상 일자</strong>로 부여하며, 표기용 <code>created</code> (시각 포함)와 정렬용 <code>date</code> 는 동일 시각을 사용한다.</li><li><strong>FR-3</strong>: 강의 목록·사이드바·인덱스는 <strong>강의 번호(<code>mNNN[.k]</code>) 오름차순 = 학습 순서</strong>로 정렬한다(본 저장소 &quot;최신 먼저&quot; 기본의 명시적 예외 — Assumptions 참조).</li><li><strong>FR-4</strong>: 각 강의가 참조하는 모든 이미지를 해석하여 사이트 정적 자산 위치로 복사하고, 본문 이미지 링크를 VitePress 에서 작동하는 표준 마크다운 이미지로 재작성한다. 특히 본문의 <code>app/static/X</code> 참조를 실제 위치 <code>static/X</code> 로 해소한다.</li><li><strong>FR-5</strong>: 이미지 해석에 실패한 항목(원본 부재 등)은 빌드를 깨지 않도록 처리하고, 실패 목록을 리포트에 남긴다.</li><li><strong>FR-6</strong>: 각 강의의 실행 예제 소스 <code>m*.py</code> 를 강의와 매핑하여, 해당 강의 페이지 <strong>말미에 &quot;전체 예제 코드&quot; 코드펜스로 인라인</strong> 삽입한다. 본문 중간의 코드 블록은 그대로 보존한다. 예제 매핑은 <strong>파일 stem 1:1</strong>(<code>m107.0.py</code>↔<code>m107.0.md</code>)이며, <code>m107.0/.1/.2</code> 는 각각 <strong>별도 강의</strong>로 취급한다. 대응 예제가 없으면 해당 블록을 생략한다.</li><li><strong>FR-7</strong>: 변환 결과가 VitePress strict 빌드를 통과한다 — 깨진 내부 링크 0, Vue 템플릿 해석 충돌(<code>{{ }}</code>, 처리되지 않은 인라인 패턴 등)로 인한 빌드 실패 0.</li><li><strong>FR-8</strong>: 새 섹션의 진입 <code>index.md</code> 와 사이드바·상단 내비게이션을 생성/등록하여 기존 섹션(cowork·hermes·blog-archive)과 동일한 방식으로 콘텐츠가 노출된다. 사이드바는 <strong>강의 번호 오름차순 평면 목록</strong>으로 구성한다(주제별 그룹화 없음).</li><li><strong>FR-9</strong>: 스크립트는 재실행 가능(idempotent)하다. 재실행 시 이전 산출물을 안전하게 갱신하며, 중복 파일이나 고아 자산을 남기지 않는다.</li><li><strong>FR-10</strong>: 실행 종료 시 요약 리포트를 출력한다(변환된 강의 수, 복사된 이미지 수, 연결된 예제 수, 건너뛴·실패 항목과 사유).</li><li><strong>FR-11</strong>: 원본 소스 디렉터리(<code>../llm-main</code>)는 읽기 전용으로 취급하며 어떤 파일도 수정·삭제하지 않는다.</li><li><strong>FR-12</strong>: 비-게시 자산(노트북·CSV·벡터DB·<code>.db</code>·운영/생성 스크립트)은 임포트 대상에서 제외한다 — Non-goals 의 목록을 명시적으로 건너뛴다.</li><li><strong>FR-13</strong>: 기존 임포트/동기화 스크립트(<code>scripts/import-hexo-blog.*</code>, <code>scripts/sync-*.{ps1,sh}</code>)와 일관된 위치·호출 방식으로 제공하여, 빌드 파이프라인/기여자가 동일한 흐름으로 실행할 수 있다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>소스 강의(Source Lesson)</strong>: <code>../llm-main</code> 의 <code>m*.md</code> 파일. 프런트매터가 없고 본문 첫 헤딩에 제목이 있으며, 이미지와 예제 코드를 참조한다.</li><li><strong>예제 소스(Example Source)</strong>: 강의에 대응하는 <code>m*.py</code> 파일. 강의에서 보거나 받을 수 있도록 연결되는 실행 코드.</li><li><strong>이미지 자산(Image Asset)</strong>: <code>static/</code> 의 png/jpg. 본문에서 <code>app/static/...</code> 접두로(경로 불일치 상태로) 참조된다.</li><li><strong>임포트 섹션(Imported Section)</strong>: 변환 결과가 들어갈 VitePress 사이트의 새 최상위 섹션 <code>/llm/</code>(인덱스 + 강의 + 사이드바 + 내비 항목).</li><li><strong>임포트 리포트(Import Report)</strong>: 1회 실행 결과 요약(처리/복사/연결/실패 집계).</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 단일 명령 한 번으로 소스의 모든 강의가 VitePress <code>/llm/</code> 섹션에 나타난다(수동 파일 편집 0건).</li><li><strong>SC-2</strong>: 변환 직후 <code>npm run build</code>(strict)가 성공한다 — 깨진 내부 링크·템플릿 충돌로 인한 실패 0건.</li><li><strong>SC-3</strong>: 임포트된 강의에서 표본 검수 시 이미지 표시율 100%(원본에 존재하는 이미지 기준), 깨진 이미지 0건 — <code>app/static/</code> 경로 불일치가 모두 해소된다.</li><li><strong>SC-4</strong>: 각 강의에서 대응 예제 코드를 보거나 받을 수 있다(강의↔예제 매핑 누락 0건, 예제가 존재하는 강의 기준).</li><li><strong>SC-5</strong>: 스크립트를 연속 2회 실행해도 사이트 산출물이 동일하다(중복·고아 파일 0건) — 재실행 안전성 확인.</li><li><strong>SC-6</strong>: 새 섹션이 상단 내비게이션과 사이드바에서 접근 가능하며, 강의가 <strong>학습 순서(번호 오름차순)</strong> 로 나열된다.</li><li><strong>SC-7</strong>: 실행 후 리포트로 처리 건수와 실패 항목을 즉시 확인할 수 있어, 누락 여부를 추가 조사 없이 판단할 수 있다.</li><li><strong>SC-8</strong>: 원본 <code>../llm-main</code> 의 모든 파일이 실행 전후로 변경되지 않으며, 제외 대상(노트북·데이터 산출물·운영 스크립트)은 사이트 산출물에 포함되지 않는다.</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li><strong>정렬 예외</strong>: 본 저장소 규칙(CLAUDE.md)의 기본은 &quot;최신 먼저&quot;지만, 본 콘텐츠는 순차적으로 따라가는 <strong>강의 시리즈</strong>이므로 학습 순서를 보존하기 위해 강의 번호 <strong>오름차순</strong>으로 정렬한다. 이것이 &quot;특별한 이유&quot;에 해당하는 명시적 예외다.</li><li>강의에는 작성일시 메타가 없으므로 <code>created</code>/<code>date</code> 는 <strong>강의 번호 기반 가상 일자</strong>로 생성한다(번호 순서대로 단조 증가). 표기·정렬이 어긋나지 않게 동일 값을 사용한다. (Clarification 2026-06-03)</li><li>새 섹션 경로는 <code>/llm/</code> 로 하고, 기존 섹션과 충돌하지 않는 단일 최상위 경로를 사용한다. 사이드바는 <strong>번호순 평면 목록</strong>이다(주제별 그룹화 없음). 섹션 라벨은 한국어 콘텐츠에 맞춰 한글로 둔다(구현 시 확정).</li><li>예제 코드는 <strong>강의 본문 말미에 코드펜스로 인라인</strong>한다(별도 페이지·다운로드 아님). (Clarification 2026-06-03)</li><li>구현 언어는 선례(008)와 동일하게 <strong>Node ESM 단일 스크립트</strong>(의존 0)를 기본으로 하고, 선례 일관성을 위해 얇은 <code>.ps1</code>/<code>.sh</code> 래퍼를 둘 수 있다.</li><li>생성물 <code>blog/llm/**</code> 는 <strong>커밋</strong>되어 CI 가 소비한다 — 임포터는 원본 <code>../llm-main</code> 을 읽으므로 CI(빌드)에서는 실행되지 않는다.</li></ul><h2 id="open-questions-해소됨" tabindex="-1">Open Questions (해소됨) <a class="header-anchor" href="#open-questions-해소됨" aria-label="Permalink to &quot;Open Questions (해소됨)&quot;">​</a></h2><ul><li>[x] 강의 작성일시(<code>created</code>/<code>date</code>) 산정 기준 → <strong>강의 번호 기반 가상 일자</strong> (번호 순 단조 증가). Clarifications 2026-06-03.</li><li>[x] 예제 <code>.py</code> 노출 형태 → <strong>강의 본문 말미 인라인 코드펜스</strong>. Clarifications 2026-06-03.</li></ul>',26)])])}const u=e(c,[["render",i]]);export{p as __pageData,u as default};
